from pathlib import Path
import json
import re
import unicodedata

def normalize(s):
    s = unicodedata.normalize('NFKC', s)
    s = s.replace('\u2014', '-').replace('\u2013', '-')
    s = s.replace('\u2019', "'").replace('\u2018', "'")
    s = s.replace('\u201c', '"').replace('\u201d', '"')
    s = re.sub(r'[();:!?]', '', s)
    s = re.sub(r'[,.](?!\d)', '', s)
    s = s.lower()
    s = re.sub(r'\s+', ' ', s).strip()
    return s

EXPECTED_SUBJECT = "AP APPROVAL REQUIRED: Great Lakes Furniture & Design Co. - $7,900.00 - Invoice GLFD-0441"

EXPECTED_BODY = (
    "A non-PO invoice requires your approval before payment can be processed.\n"
    "Vendor: Great Lakes Furniture & Design Co. (V-00009).\n"
    "Invoice: GLFD-0441, dated 2026-03-20\n"
    "Amount: $7,900.00.\n"
    "Description: Executive conference table, 10-person, walnut finish.\n"
    "GL Code: 1000-100-6200.\n"
    "Please reply APPROVED or REJECTED with reason.\n"
    "If no response is received within 5 business days, the invoice will be placed on APPR hold and the vendor will be notified of the delay."
)

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox"}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"mailbox.json not found at {mailbox_path}"}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse mailbox.json: {e}"}

    emails = data.get('emails', [])
    drafts = [e for e in emails if str(e.get('folder', '')).lower() == 'drafts']

    if not drafts:
        return {"pass": False, "score": 0.0, "feedback": "No emails found in Drafts folder"}

    # Pick best matching draft by subject keywords
    best_draft = drafts[0]
    best_score = -1
    for draft in drafts:
        subject = str(draft.get('subject', '')).lower()
        score = ('glfd-0441' in subject) + ('great lakes' in subject)
        if score > best_score:
            best_score = score
            best_draft = draft

    draft = best_draft

    to_raw = draft.get('to_addr', '') or draft.get('to', '') or ''
    if isinstance(to_raw, list):
        to_addr = ' '.join([str(x).lower().strip() for x in to_raw])
    else:
        to_addr = str(to_raw).lower()

    cc_raw = draft.get('cc_addr', '') or draft.get('cc', '') or ''
    if isinstance(cc_raw, list):
        cc_addr = ' '.join([str(x).lower().strip() for x in cc_raw])
    else:
        cc_addr = str(cc_raw).lower()

    subject = str(draft.get('subject', ''))
    body = str(draft.get('body_text', '') or draft.get('body', '') or '')

    checks = {
        'to: m.chen@meridianpartners.com': 'm.chen@meridianpartners.com' in to_addr,
        'to: r.whitfield@meridianpartners.com': 'r.whitfield@meridianpartners.com' in to_addr,
        'cc: ap@meridianpartners.com': 'ap@meridianpartners.com' in cc_addr,
        'subject exact match': normalize(subject) == normalize(EXPECTED_SUBJECT),
        'body exact match': normalize(body) == normalize(EXPECTED_BODY),
    }

    failed = [k for k, v in checks.items() if not v]
    passed = [k for k, v in checks.items() if v]
    score = len(passed) / len(checks)

    if not failed:
        return {"pass": True, "score": 1.0, "feedback": f"Draft email verified: all {len(checks)} checks passed."}

    details = f"Failed: {', '.join(failed)}. Passed: {', '.join(passed)}."
    if 'subject exact match' in failed:
        details += f" Subject found: '{subject}'."
    if 'body exact match' in failed:
        norm_actual = normalize(body)
        norm_expected = normalize(EXPECTED_BODY)
        if norm_actual == norm_expected:
            details += " Body: normalized content matches — difference is line-break/formatting only."
        else:
            actual_words = norm_actual.split()
            expected_words = norm_expected.split()
            divergence = None
            for i, (aw, ew) in enumerate(zip(actual_words, expected_words)):
                if aw != ew:
                    start = max(0, i - 3)
                    expected_ctx = ' '.join(expected_words[start:i+6])
                    actual_ctx = ' '.join(actual_words[start:i+6])
                    divergence = f"First divergence at word {i+1}: expected '...{expected_ctx}...' | got '...{actual_ctx}...'"
                    break
            if divergence is None:
                divergence = f"Word count differs: expected {len(expected_words)}, got {len(actual_words)}"
            details += f" Body diff: {divergence}"


    return {"pass": False, "score": score, "feedback": details}

