            data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to parse slack_data.json: {e}"}

    messages = data.get('messages', {})

    # Look for any messages that mention Great Lakes, GLFD-0441, or 7900 that might have been sent by the agent
    # The task says 'No new Slack messages are sent'
    # We check if there are any messages related to this invoice task
    task_related_messages = []
    for channel_id, msgs in messages.items():
        if not isinstance(msgs, list):
            continue
        for msg in msgs:
            if not isinstance(msg, dict):
                continue
            text = str(msg.get('text', '')).lower()
            if (
                'great lakes' in text
                or 'glfd-0441' in text
                or 'glfd0441' in text
                or ('7,900' in text and 'furniture' in text)
                or ('7900' in text and 'furniture' in text)
            ):
                task_related_messages.append({'channel': channel_id, 'text': msg.get('text', '')[:100]})

    if task_related_messages:
        return {"pass": False, "score": 0.0, "feedback": f"Found {len(task_related_messages)} Slack message(s) related to Great Lakes/GLFD-0441 that should not have been sent: {task_related_messages}"}

    return {"pass": True, "score": 1.0, "feedback": "No Slack messages related to Great Lakes Furniture or GLFD-0441 found, as expected"}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('*.xlsx'))
    if not xlsx_files:
        return {"pass": False, "score": 0.0, "feedback": "No .xlsx file found in workspace"}

    ledger_files = [f for f in xlsx_files if 'ledger' in f.name.lower() or 'ap' in f.name.lower()]
    target_files = ledger_files if ledger_files else xlsx_files

    for fpath in target_files:
        try:
            wb = openpyxl.load_workbook(fpath, data_only=True)
            ws = wb["Invoice Register"] if "Invoice Register" in wb.sheetnames else wb.worksheets[0]

            status_col = None
            for col in range(1, ws.max_column + 1):
                hdr = ws.cell(row=1, column=col).value
                if hdr is not None and str(hdr).strip().lower() == "status":
                    status_col = col
                    break

            if status_col is None:
                return {"pass": False, "score": 0.0, "feedback": f"Could not find 'Status' column header in {fpath.name}"}

            populated_after_status = []
            for col in range(status_col + 1, ws.max_column + 1):
                cell_value = ws.cell(row=13, column=col).value
                if cell_value is None:
                    continue
                if cell_value == 0 or cell_value == 0.0:
                    continue
                if str(cell_value).strip() == "" or str(cell_value).strip() == "0":
                    continue
                col_header = ws.cell(row=1, column=col).value
                populated_after_status.append((col, col_header, cell_value))

            if not populated_after_status:
                return {"pass": True, "score": 1.0, "feedback": f"Row 13 has no populated fields after 'Status' (column {status_col})"}
            else:
                details = "; ".join([f"Col {c} ('{h}'): '{v}'" for c, h, v in populated_after_status])
                return {"pass": False, "score": 0.0, "feedback": f"Row 13 has {len(populated_after_status)} populated field(s) after 'Status': {details}"}

        except Exception as e:
            continue

    return {"pass": False, "score": 0.0, "feedback": "Could not find or read ap_ledger.xlsx"}

